import api from './api';
import type {
  ApiResponse,
  User,
  CreateUserPayload,
  UpdateUserPayload,
} from '@/types/index';

export interface UserListParams {
  role?: string;
  search?: string;
  page?: number;
  limit?: number;
}

export interface UserListResponse {
  users: User[];
  total: number;
  page: number;
  limit: number;
  totalPages: number;
}

export const userService = {
  async getUsers(params?: UserListParams): Promise<UserListResponse> {
    const res = await api.get<ApiResponse<UserListResponse>>('/users', { params });
    return res.data.data;
  },

  async getUserById(id: string): Promise<User> {
    const res = await api.get<ApiResponse<{ user: User }>>(`/users/${id}`);
    return res.data.data.user;
  },

  async createUser(payload: CreateUserPayload): Promise<User> {
    const res = await api.post<ApiResponse<{ user: User }>>('/users', payload);
    return res.data.data.user;
  },

  async updateUser(id: string, payload: UpdateUserPayload): Promise<User> {
    const res = await api.put<ApiResponse<{ user: User }>>(`/users/${id}`, payload);
    return res.data.data.user;
  },

  async deleteUser(id: string): Promise<void> {
    await api.delete(`/users/${id}`);
  },

  async getTechLeads(): Promise<User[]> {
    const res = await api.get<ApiResponse<{ users: User[] }>>('/users/tech-leads');
    return res.data.data.users;
  },

  async getManagers(): Promise<User[]> {
    const res = await api.get<ApiResponse<{ users: User[] }>>('/users/managers');
    return res.data.data.users;
  },
};
