import api from './api';
import type {
  ApiResponse,
  Appraisal,
  Comment,
  CreateAppraisalPayload,
  UpdateAppraisalPayload,
} from '@/types/index';

export interface AppraisalListParams {
  status?: string;
  year?: number;
  page?: number;
  limit?: number;
}

export interface AppraisalListResponse {
  appraisals: Appraisal[];
  total: number;
  page: number;
  limit: number;
  totalPages: number;
}

export const appraisalService = {
  async getAppraisals(params?: AppraisalListParams): Promise<AppraisalListResponse> {
    const res = await api.get<ApiResponse<AppraisalListResponse>>('/appraisals', { params });
    return res.data.data;
  },

  async getAppraisalById(id: string): Promise<Appraisal> {
    const res = await api.get<ApiResponse<{ appraisal: Appraisal }>>(`/appraisals/${id}`);
    return res.data.data.appraisal;
  },

  async createAppraisal(payload: CreateAppraisalPayload): Promise<Appraisal> {
    const res = await api.post<ApiResponse<{ appraisal: Appraisal }>>('/appraisals', payload);
    return res.data.data.appraisal;
  },

  async updateAppraisal(id: string, payload: UpdateAppraisalPayload): Promise<Appraisal> {
    const res = await api.put<ApiResponse<{ appraisal: Appraisal }>>(`/appraisals/${id}`, payload);
    return res.data.data.appraisal;
  },

  async submitAppraisal(id: string): Promise<Appraisal> {
    const res = await api.post<ApiResponse<{ appraisal: Appraisal }>>(`/appraisals/${id}/submit`);
    return res.data.data.appraisal;
  },

  async addComment(id: string, comment: string): Promise<Comment> {
    const res = await api.post<ApiResponse<{ comment: Comment }>>(`/appraisals/${id}/comments`, {
      comment,
    });
    return res.data.data.comment;
  },

  async getComments(id: string): Promise<Comment[]> {
    const res = await api.get<ApiResponse<{ comments: Comment[] }>>(`/appraisals/${id}/comments`);
    return res.data.data.comments;
  },
};
