import api from './api';
import type { ApiResponse, DashboardStats, TeamAppraisal, AnalyticsData } from '@/types/index';

export const dashboardService = {
  async getDashboardStats(): Promise<DashboardStats> {
    const res = await api.get<ApiResponse<DashboardStats>>('/dashboard/stats');
    return res.data.data;
  },

  async getTeamAppraisals(): Promise<TeamAppraisal[]> {
    const res = await api.get<ApiResponse<{ appraisals: TeamAppraisal[] }>>('/dashboard/team');
    return res.data.data.appraisals;
  },

  async getTeamAnalytics(): Promise<AnalyticsData> {
    const res = await api.get<ApiResponse<AnalyticsData>>('/dashboard/analytics');
    return res.data.data;
  },
};
