import api from './api';
import type { ApiResponse, QuestionSection, Question } from '@/types/index';

export const questionService = {
  async getQuestions(): Promise<QuestionSection[]> {
    const res = await api.get<ApiResponse<{ sections: QuestionSection[] }>>('/questions');
    return res.data.data.sections;
  },

  async getQuestionsBySection(section: string): Promise<QuestionSection> {
    const res = await api.get<ApiResponse<{ section: QuestionSection }>>(
      `/questions/section/${section}`
    );
    return res.data.data.section;
  },

  async getQuestionById(id: string): Promise<Question> {
    const res = await api.get<ApiResponse<{ question: Question }>>(`/questions/${id}`);
    return res.data.data.question;
  },
};
